SELECT reference_id, genome_id, MAX(iterations) AS max_iterations, MAX(coverage) AS max_coverage
FROM genomic_data
GROUP BY reference_id, genome_id;

SELECT position, coverage
FROM genomic_data
WHERE reference_id = 'R12345' AND genome_id = 'G67890';

SELECT g.genome_name
FROM genomes g
JOIN (
    SELECT genome_id
    FROM genomic_data
    WHERE iterations = (
        SELECT MAX(iterations)
        FROM genomic_data
    )
) gd ON g.genome_id = gd.genome_id;

SELECT COUNT(*)
FROM genomic_data
WHERE genome_id = 'hg19';

SELECT coverage
FROM genomic_data
WHERE reference_id = 'specific_reference_id' AND position = 12345;

SELECT position
FROM genomic_data
WHERE coverage = (SELECT MAX(coverage) FROM genomic_data);

SELECT coverage
FROM genomic_data
ORDER BY coverage DESC;

SELECT genome_id, genome_name, species
FROM genomes
WHERE genome_id = 'specific_genome_id';

SELECT COUNT(*) AS sequence_count
FROM genomic_data
WHERE genome_id = 'specific_genome_id' AND position BETWEEN 1000 AND 2000;

SELECT reference_id, genome_id
FROM genomic_data
WHERE coverage > 50;
